import{_ as a,o as t,c as o,ak as n}from"./chunks/framework.CI25veif.js";const m=JSON.parse('{"title":"ExternalAppHost","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-externalapps-winforms-externalapphost.md","filePath":"api/reference/royalapps-community-externalapps-winforms-externalapphost.md"}'),r={name:"api/reference/royalapps-community-externalapps-winforms-externalapphost.md"};function i(s,e,p,d,c,l){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="externalapphost" tabindex="-1"><code>ExternalAppHost</code> <a class="header-anchor" href="#externalapphost" aria-label="Permalink to “ExternalAppHost”">​</a></h1><p>The host control which can embed external application windows.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.ExternalApps.WinForms.ExternalAppHost</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="attachmentstate-attachmentstate" tabindex="-1"><code>AttachmentState</code> (<a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-embedding-attachmentstate">AttachmentState</a>) <a class="header-anchor" href="#attachmentstate-attachmentstate" aria-label="Permalink to “AttachmentState (AttachmentState)”">​</a></h3><p>Gets how the current external window is attached to the host.</p><h3 id="embeddedwindowhandle-intptr" tabindex="-1"><code>EmbeddedWindowHandle</code> (<code>IntPtr</code>) <a class="header-anchor" href="#embeddedwindowhandle-intptr" aria-label="Permalink to “EmbeddedWindowHandle (IntPtr)”">​</a></h3><p>Gets the handle of the currently tracked external window, or <code>System.IntPtr.Zero</code> when no window is attached.</p><h3 id="isembedded-bool" tabindex="-1"><code>IsEmbedded</code> (<code>bool</code>) <a class="header-anchor" href="#isembedded-bool" aria-label="Permalink to “IsEmbedded (bool)”">​</a></h3><p>Gets a value indicating whether the current window is embedded in the host control.</p><h3 id="loggerfactory-iloggerfactory" tabindex="-1"><code>LoggerFactory</code> (<code>ILoggerFactory</code>) <a class="header-anchor" href="#loggerfactory-iloggerfactory" aria-label="Permalink to “LoggerFactory (ILoggerFactory)”">​</a></h3><p>Gets or sets the logger factory used to create host loggers.</p><h3 id="options-externalappoptions" tabindex="-1"><code>Options</code> (<a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-options-externalappoptions">ExternalAppOptions</a>?) <a class="header-anchor" href="#options-externalappoptions" aria-label="Permalink to “Options (ExternalAppOptions?)”">​</a></h3><p>Gets the options used by the current session, or <code>null</code> when no session is active.</p><h3 id="process-process" tabindex="-1"><code>Process</code> (<code>Process</code>?) <a class="header-anchor" href="#process-process" aria-label="Permalink to “Process (Process?)”">​</a></h3><p>Gets the tracked process for the current session, or <code>null</code> when no process is attached.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><h3 id="applicationactivated" tabindex="-1"><code>ApplicationActivated</code> <a class="header-anchor" href="#applicationactivated" aria-label="Permalink to “ApplicationActivated”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<code>EventArgs</code>&gt;?</p><p>Occurs when the embedded application receives focus.</p><h3 id="applicationclosed" tabindex="-1"><code>ApplicationClosed</code> <a class="header-anchor" href="#applicationclosed" aria-label="Permalink to “ApplicationClosed”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-events-applicationclosedeventargs">ApplicationClosedEventArgs</a>&gt;?</p><p>Occurs when the tracked application closes or the session terminates with an error.</p><h3 id="applicationstarted" tabindex="-1"><code>ApplicationStarted</code> <a class="header-anchor" href="#applicationstarted" aria-label="Permalink to “ApplicationStarted”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<code>EventArgs</code>&gt;?</p><p>Occurs after the application has started and any initial embedding work has completed.</p><h3 id="windowselectionrequested" tabindex="-1"><code>WindowSelectionRequested</code> <a class="header-anchor" href="#windowselectionrequested" aria-label="Permalink to “WindowSelectionRequested”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-events-windowselectionrequesteventargs">WindowSelectionRequestEventArgs</a>&gt;?</p><p>Occurs while candidate windows are being discovered and allows the consumer to choose the window to embed.</p><h3 id="windowtitlechanged" tabindex="-1"><code>WindowTitleChanged</code> <a class="header-anchor" href="#windowtitlechanged" aria-label="Permalink to “WindowTitleChanged”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-events-windowcaptioneventargs">WindowCaptionEventArgs</a>&gt;?</p><p>Occurs when the tracked window caption changes.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="closeapplication" tabindex="-1"><code>CloseApplication()</code> <a class="header-anchor" href="#closeapplication" aria-label="Permalink to “CloseApplication()”">​</a></h3><p>Returns: <code>void</code></p><p>Requests that the tracked application is closed.</p><p>Depending on the application, this may show confirmation dialogs. If <a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-options-externalapplaunchoptions">ExternalAppLaunchOptions.KillOnClose</a> is enabled, the process is terminated when graceful shutdown fails.</p><h3 id="focusapplication-bool" tabindex="-1"><code>FocusApplication(bool)</code> <a class="header-anchor" href="#focusapplication-bool" aria-label="Permalink to “FocusApplication(bool)”">​</a></h3><p>Returns: <code>void</code></p><p>Transfers focus to the tracked application.</p><p><strong>Parameters</strong></p><ul><li><code>force</code> (<code>bool</code>): <code>true</code> to focus even when the window is detached; otherwise, focus is applied only while embedded.</li></ul><h3 id="setwindowposition" tabindex="-1"><code>SetWindowPosition()</code> <a class="header-anchor" href="#setwindowposition" aria-label="Permalink to “SetWindowPosition()”">​</a></h3><p>Repositions the tracked application window to match the current host bounds.</p><h3 id="setwindowposition-rectangle" tabindex="-1"><code>SetWindowPosition(Rectangle)</code> <a class="header-anchor" href="#setwindowposition-rectangle" aria-label="Permalink to “SetWindowPosition(Rectangle)”">​</a></h3><p>Returns: <code>void</code></p><p>Moves and resizes the tracked application window to the specified bounds.</p><p><strong>Parameters</strong></p><ul><li><code>rectangle</code> (<code>Rectangle</code>): The target bounds, in host coordinates when embedded or screen coordinates when detached.</li></ul><h3 id="start-externalappoptions" tabindex="-1"><code>Start(ExternalAppOptions)</code> <a class="header-anchor" href="#start-externalappoptions" aria-label="Permalink to “Start(ExternalAppOptions)”">​</a></h3><p>Returns: <code>void</code></p><p>Starts a new external application session with the specified options.</p><p><strong>Parameters</strong></p><ul><li><code>options</code> (<a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-options-externalappoptions">ExternalAppOptions</a>): The runtime options that control launch, selection, and embedding behavior.</li></ul><p>This method schedules the startup workflow on a background task and returns immediately. Subscribe to <a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-externalapphost">ExternalAppHost.ApplicationStarted</a>, <a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-externalapphost">ExternalAppHost.ApplicationClosed</a>, and <a href="/royalapps-community-externalapps/api/reference/royalapps-community-externalapps-winforms-externalapphost">ExternalAppHost.WindowSelectionRequested</a> to observe progress.</p><p><a href="./../">Back to API index</a></p>',57)])])}const w=a(r,[["render",i]]);export{m as __pageData,w as default};
